-		return actual != expected
+		return math.Abs(actual-expected) >= floatEpsilon
 	case "gt":
 		return actual > expected
 	case "gte":
-		return actual >= expected
+		return actual >= expected || math.Abs(actual-expected) < floatEpsilon
 	case "lt":
-		return actual < expected
+		return actual < expected && math.Abs(actual-expected) >= floatEpsilon
 	case "lte":
-		return actual <= expected
+		return actual <= expected || math.Abs(actual-expected) < floatEpsilon
 	default:
 		return false
 	}
